module RefModule(
    input A,
    input B,
    input CIN,
    output SUM,
    output COUT
);wire w1, w2, w3;

// Calculate SUM
assign w1 = A ^ B;
assign SUM = w1 ^ CIN;

// Calculate COUT
  wire temp1_A = A;
  wire temp2_B = B;
  assign w2 = temp1_A & temp2_B;
assign w3 = CIN & w1;
assign COUT = w2 | w3;

endmodule
